    91→
    92→  const attributeRelevance: AttributeRelevanceMatrix = {
    93→    RolesLegend: {
    94→      CORE: 'Core attribute',
    95→      PRIMARY_BOOST: 'Primary boost',
    96→      SECONDARY_BOOST: 'Secondary boost',
    97→      DISAMBIGUATOR: 'Disambiguator',
    98→      FILTER: 'Filter',
    99→      STRUCTURAL: 'Structural',
   100→      DERIVED_LINK: 'Derived link',
   101→      NEUTRAL: 'Neutral',
   102→    },
   103→  };
