   106→    featureExtraction: {
   107→      systemPrompt: ['Extract features'],
   108→      userPrompt: ['Analyze email'],
   109→      temperature: 0.1,
   110→      maxTokens: 1000,
   111→    },
   112→    finalClassification: {
   113→      systemPrompt: ['Classify email'],
   114→      userPrompt: ['Determine category'],
   115→      temperature: 0.1,
   116→      maxTokens: 500,
   117→    },
   118→  };
   119→
   120→  const featureExtractionSchema: JSONSchema = {
   121→    type: 'object',
   122→    properties: {},
   123→    required: [],
   124→    additionalProperties: false,
   125→  };
   126→
   127→  const processingConfig: ProcessingConfig = {
