   172→        name: 'Store Receipts',
   173→        raw: 'Store Receipts <receipts@store.com>',
   174→      },
   175→      to: [
   176→        {
   177→          email: 'customer@example.com',
   178→          name: 'Customer',
   179→          raw: 'Customer <customer@example.com>',
   180→        },
   181→      ],
   182→      date: new Date('2025-09-28T14:30:00Z'),
   183→      bodyPlain: `Thank you for your purchase!
   184→
   185→Order Details:
   186→- Order #: INV-2024-001
   187→- Total: $129.99
   188→- Payment Method: Credit Card ending in 4567
   189→- Date: September 28, 2025
   190→
   191→Items:
   192→1. Wireless Headphones - $99.99
   193→2. Shipping - $9.99
   194→3. Tax - $20.01
   195→
   196→Your order will be shipped within 2 business days.`,
   197→      bodyHtml: '<h1>Thank you for your purchase!</h1><p>Total: $129.99</p>',
   198→      payload: {
   199→        mimeType: 'text/plain',
   200→        headers: [
   201→          { name: 'Message-ID', value: '<receipt-001@store.com>' },
   202→          { name: 'From', value: 'Store Receipts <receipts@store.com>' },
   203→          { name: 'Subject', value: 'Receipt for your purchase - Order #INV-2024-001' },
   204→        ],
   205→      },
   206→      isProcessed: false,
   207→      processingPriority: 1,
   208→    };
   209→
   210→    // Mock configuration with realistic rule patterns
   211→    mockConfig = {
   212→      settings: {
   213→        useLexicalPatterns: true,
   214→        applySubtypeRules: true,
   215→        boundedAggregation: true,
   216→      },
   217→      topLevelCategories: {
   218→        financial: {
   219→          description: 'Financial communications',
   220→          subtypes: {
   221→            receipt: {
   222→              description: 'Purchase receipts and confirmations',
   223→              derived: false,
   224→              parallelSafe: true,
   225→              ruleBasedClassification: {
   226→                highConfidence: [
   227→                  {
   228→                    field: 'subject',
   229→                    operation: 'containsAny',
   230→                    values: ['receipt', 'payment confirmation', 'order confirmation'],
   231→                    weight: 12,
   232→                  },
   233→                ],
   234→                mediumConfidence: [
   235→                  {
   236→                    field: 'body',
   237→                    operation: 'containsAny',
   238→                    values: ['total', 'amount', 'charged', 'purchase'],
   239→                    weight: 6,
   240→                  },
   241→                  {
   242→                    field: 'body',
   243→                    operation: 'regexAny',
   244→                    values: ['\\$\\d+\\.\\d{2}', 'USD \\d+'],
   245→                    weight: 8,
   246→                  },
   247→                ],
   248→                lowConfidence: [
   249→                  {
   250→                    field: 'subject',
   251→                    operation: 'containsAny',
   252→                    values: ['order', 'item'],
   253→                    weight: 3,
   254→                  },
   255→                ],
   256→              },
   257→            },
   258→            invoice: {
   259→              description: 'Invoices and billing statements',
   260→              derived: false,
   261→              parallelSafe: true,
   262→              ruleBasedClassification: {
   263→                highConfidence: [
   264→                  {
   265→                    field: 'subject',
   266→                    operation: 'containsAny',
   267→                    values: ['invoice', 'bill', 'statement'],
   268→                    weight: 12,
   269→                  },
   270→                ],
   271→              },
   272→            },
   273→          },
   274→          aiFinalClassification: {
   275→            categoryDescription: 'Financial and monetary communications',
   276→            decisionCriteria: ['Contains financial transactions or account information'],
   277→          },
   278→        },
   279→        actionable: {
   280→          description: 'Action-required emails',
   281→          subtypes: {
   282→            explicitAction: {
   283→              description: 'Emails with explicit action requests',
   284→              derived: false,
   285→              parallelSafe: true,
   286→              ruleBasedClassification: {
   287→                highConfidence: [
   288→                  {
   289→                    field: 'subject',
   290→                    operation: 'startsWith',
   291→                    values: ['TODO:', 'ACTION:', 'TASK:', 'URGENT:'],
   292→                    weight: 15,
   293→                  },
   294→                ],
   295→                mediumConfidence: [
   296→                  {
   297→                    field: 'body',
   298→                    operation: 'containsAny',
   299→                    values: ['please review', 'action required', 'respond by'],
   300→                    weight: 7,
   301→                  },
   302→                ],
   303→              },
   304→            },
   305→          },
   306→          aiFinalClassification: {
   307→            categoryDescription: 'Emails requiring user action',
   308→            decisionCriteria: ['Contains explicit or implicit action requests'],
   309→          },
   310→        },
   311→      },
   312→      tuningParameters: {
   313→        KHigh: 2,
   314→        KMedium: 2,
   315→        KLow: 2,
   316→        TAIL_DAMPEN: 0.5,
   317→        TAIL_RATIO_CAP: 0.3,
   318→        aggregationCap: 1.0,
   319→      },
   320→    };
   321→  });
   322→
   323→  describe('Configuration Validation', () => {
   324→    it('should validate valid configuration successfully', () => {
   325→      const result = RuleScoringStageConfigSchema.safeParse(mockConfig);
   326→      expect(result.success).toBe(true);
   327→    });
   328→
   329→    it('should reject invalid tuning parameters', () => {
   330→      const invalidConfig = {
   331→        ...mockConfig,
   332→        topLevelCategories: {}, // Empty categories
   333→        tuningParameters: {
   334→          ...mockConfig.tuningParameters,
   335→          KHigh: -1, // Invalid - must be >= 0
   336→          KMedium: -0.5, // Invalid - must be >= 0
   337→          KLow: -0.3, // Invalid - must be >= 0
   338→        },
   339→      };
   340→
   341→      const result = RuleScoringStageConfigSchema.safeParse(invalidConfig);
   342→      expect(result.success).toBe(false);
   343→      expect(result.error?.issues.length).toBeGreaterThanOrEqual(3); // At least 3 errors (KHigh, KMedium, KLow)
   344→    });
   345→
   346→    it('should reject unknown rule operations', () => {
   347→      const invalidConfig = {
   348→        ...mockConfig,
   349→        topLevelCategories: {
   350→          financial: {
   351→            description: 'Test',
   352→            subtypes: {
   353→              test: {
   354→                description: 'Test',
   355→                ruleBasedClassification: {
   356→                  highConfidence: [
   357→                    {
   358→                      field: 'subject',
   359→                      operation: 'invalidOperation' as string,
   360→                      values: ['test'],
   361→                      weight: 10,
   362→                    },
   363→                  ],
   364→                },
   365→              },
   366→            },
   367→          },
   368→        },
   369→      };
   370→
   371→      const result = RuleScoringStageConfigSchema.safeParse(invalidConfig);
   372→      expect(result.success).toBe(false);
   373→    });
   374→  });
   375→
   376→  describe('executeRuleScoring()', () => {
   377→    it('should process emails with rule matches successfully', () => {
   378→      const { session, result } = setupTest();
   379→      result.emailId = mockEmail.id;
   380→      executeRuleScoring(mockEmail, session, result, mockConfig);
   381→
   382→      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
   383→      expect(result.explainabilityTrace.ruleScoring.length).toBeGreaterThan(0);
   384→      expect(
   385→        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
   386→      ).toBeGreaterThan(0);
   387→      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
   388→    });
   389→
   390→    it('should calculate sophisticated bounded aggregation correctly', () => {
   391→      const { session, result } = setupTest();
   392→      result.emailId = mockEmail.id;
   393→      executeRuleScoring(mockEmail, session, result, mockConfig);
   394→
   395→      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
   396→      expect(financialResult).toBeDefined();
   397→      expect(financialResult!.subtypeScores.receipt).toBeDefined();
   398→
   399→      // Should have multiple rule matches with different weights
   400→      const receiptScore = financialResult!.subtypeScores.receipt;
   401→      expect(receiptScore.ruleMatches.length).toBeGreaterThan(1);
   402→      expect(receiptScore.totalScore).toBeGreaterThan(12); // High confidence + medium matches
   403→
   404→      // Verify bounded aggregation breakdown
   405→      expect(receiptScore.aggregationBreakdown).toContain(':');
   406→      expect(financialResult!.scoringRationale[0]).toContain('Rule aggregation:');
   407→    });
   408→
   409→    it('should handle emails with no rule matches', () => {
   410→      const emptyEmail: EmailMessage = {
   411→        ...mockEmail,
   412→        subject: 'Random subject with no patterns',
   413→        bodyPlain: 'This is just random content with no matching patterns',
   414→        bodyHtml: undefined,
   415→      };
   416→
   417→      const { session, result } = setupTest();
   418→      result.emailId = emptyEmail.id;
   419→      executeRuleScoring(emptyEmail, session, result, mockConfig);
   420→
   421→      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
   422→      expect(
   423→        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
   424→      ).toBe(0);
   425→    });
   426→
   427→    it("should preserve existing scores when rules don't improve them", () => {
   428→      // Use config with higher aggregationCap to allow existing score of 25.0
   429→      const highCapConfig = {
   430→        ...mockConfig,
   431→        tuningParameters: {
   432→          ...mockConfig.tuningParameters,
   433→          aggregationCap: 100.0, // Allow high existing scores
   434→        },
   435→      };
   436→
   437→      const { session, result } = setupTest();
   438→      result.emailId = mockEmail.id;
   439→
   440→      // Set high existing score
   441→      result.scoreBreakdown.categoryScores.financial = {
   442→        baseScore: 25.0,
   443→        hardAssertionBonus: 0,
   444→        strongIndicatorScore: 0,
   445→        ruleScore: 0,
   446→        attributeInfluenceScore: 0,
   447→        finalScore: 25.0,
   448→        parallelComputedComponents: [],
   449→        computationDurationMs: 0,
   450→        cacheHits: [],
   451→        scoreAggregationSteps: [],
   452→        cappingApplied: false,
   453→      };
   454→
   455→      executeRuleScoring(mockEmail, session, result, highCapConfig);
   456→
   457→      // Should use max of existing vs rule score (both under aggregationCap)
   458→      // Rule score is 58, existing is 25, so max(25, 58) = 58
   459→      expect(result.scoreBreakdown.categoryScores.financial.finalScore).toBe(58);
   460→    });
   461→
   462→    it('should handle disabled rule scoring settings', () => {
   463→      const disabledConfig = {
   464→        ...mockConfig,
   465→        settings: {
   466→          useLexicalPatterns: false,
   467→          applySubtypeRules: false,
   468→          boundedAggregation: true,
   469→        },
   470→      };
   471→
   472→      const { session, result } = setupTest();
   473→      result.emailId = mockEmail.id;
   474→      executeRuleScoring(mockEmail, session, result, disabledConfig);
   475→
   476→      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
   477→      // Disabled config should not produce rule scoring results
   478→      expect(
   479→        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
   480→      ).toBe(0);
   481→    });
   482→
   483→    it('should update context tracking properly', () => {
   484→      const { session, result } = setupTest();
   485→      result.emailId = mockEmail.id;
   486→      executeRuleScoring(mockEmail, session, result, mockConfig);
   487→
   488→      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
   489→      expect(result.explainabilityTrace.configurationRefs.ruleScoring).toBe(
   490→        'config.processingConfig.topLevelCategories.*.subtypes.*.ruleBasedClassification'
   491→      );
   492→    });
   493→
   494→    it('should handle multiple categories with matches', () => {
   495→      const multiCategoryEmail: EmailMessage = {
   496→        ...mockEmail,
   497→        subject: 'TODO: Review receipt for meeting expenses',
   498→        bodyPlain: 'Please review the total amount charged: $50.00',
   499→      };
   500→
   501→      const { session, result } = setupTest();
   502→      result.emailId = multiCategoryEmail.id;
   503→      executeRuleScoring(multiCategoryEmail, session, result, mockConfig);
   504→
   505→      expect(
   506→        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
   507→      ).toBe(2);
   508→      expect(result.scoreBreakdown.categoryScores.financial?.finalScore).toBeGreaterThan(0);
   509→      expect(result.scoreBreakdown.categoryScores.actionable?.finalScore).toBeGreaterThan(0);
   510→
   511→      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
   512→      const actionableResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'actionable');
   513→
   514→      expect(financialResult?.selectedSubtypeId).toBe('receipt');
   515→      expect(actionableResult?.selectedSubtypeId).toBe('explicitAction');
   516→    });
   517→  });
   518→
   519→  describe('Rule Evaluation Functions', () => {
   520→    describe('containsAny operation', () => {
   521→      it('should match any value in the list', () => {
   522→        // Test subject content directly via stage execution
   523→        const testEmail = { ...mockEmail, subject: 'Your receipt is ready' };
