   530→        expect(financialResult?.ruleMatches.some((match) => match.matchedValue === 'receipt')).toBe(true);
   531→      });
   532→
   533→      it('should be case insensitive', () => {
   534→        const testEmail = { ...mockEmail, subject: 'RECEIPT for your order' };
   535→
   536→        const { session, result } = setupTest();
   537→        result.emailId = testEmail.id;
   538→        executeRuleScoring(testEmail, session, result, mockConfig);
   539→
   540→        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
   541→        expect(financialResult?.ruleMatches.some((match) => match.operation === 'containsAny')).toBe(true);
   542→      });
   543→
   544→      it('should not match when no values are found', () => {
   545→        const testEmail = { ...mockEmail, subject: 'Random subject' };
   546→
   547→        const { session, result } = setupTest();
   548→        result.emailId = testEmail.id;
