   555→          ) || [];
   556→        expect(subjectMatches.length).toBe(0);
   557→      });
   558→    });
   559→
   560→    describe('startsWith operation', () => {
   561→      it('should match prefixes correctly', () => {
   562→        const testEmail = { ...mockEmail, subject: 'TODO: Review this document' };
   563→
   564→        const { session, result } = setupTest();
   565→        result.emailId = testEmail.id;
   566→        executeRuleScoring(testEmail, session, result, mockConfig);
   567→
   568→        const actionableResult = result.explainabilityTrace.ruleScoring.find(
   569→          (cat) => cat.categoryCode === 'actionable'
   570→        );
   571→        expect(
   572→          actionableResult?.ruleMatches.some(
   573→            (match) => match.operation === 'startsWith' && match.matchedValue === 'TODO:'
   574→          )
   575→        ).toBe(true);
   576→      });
   577→
   578→      it('should be case insensitive for startsWith', () => {
   579→        const testEmail = { ...mockEmail, subject: 'todo: check this' };
   580→
   581→        const { session, result } = setupTest();
   582→        result.emailId = testEmail.id;
   583→        executeRuleScoring(testEmail, session, result, mockConfig);
   584→
   585→        const actionableResult = result.explainabilityTrace.ruleScoring.find(
   586→          (cat) => cat.categoryCode === 'actionable'
   587→        );
   588→        expect(actionableResult?.ruleMatches.length).toBeGreaterThan(0);
   589→      });
   590→    });
   591→
   592→    describe('regexAny operation', () => {
   593→      it('should match regex patterns correctly', () => {
   594→        const testEmail = { ...mockEmail, bodyPlain: 'The total cost is $129.99' };
   595→
   596→        const { session, result } = setupTest();
   597→        result.emailId = testEmail.id;
   598→        executeRuleScoring(testEmail, session, result, mockConfig);
   599→
   600→        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
   601→        const regexMatches = financialResult?.ruleMatches.filter((match) => match.operation === 'regexAny') || [];
   602→        expect(regexMatches.length).toBeGreaterThan(0);
   603→        expect(regexMatches[0].matchedValue).toMatch(/\$\d+\.\d{2}/);
   604→      });
   605→
   606→      it('should handle invalid regex gracefully', () => {
   607→        const invalidRegexConfig = {
   608→          ...mockConfig,
   609→          topLevelCategories: {
   610→            testCategory: {
   611→              description: 'Test',
   612→              subtypes: {
   613→                testSubtype: {
   614→                  description: 'Test',
   615→                  derived: false,
   616→                  parallelSafe: true,
   617→                  ruleBasedClassification: {
   618→                    mediumConfidence: [
   619→                      {
   620→                        field: 'body' as const,
   621→                        operation: 'regexAny' as const,
   622→                        values: ['[invalid regex pattern'],
   623→                        weight: 5,
   624→                      },
   625→                    ],
   626→                  },
   627→                },
   628→              },
   629→              aiFinalClassification: {
   630→                categoryDescription: 'Test category',
